import{_ as e,o as a,c as t,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"邪恶潜水鳐","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/3.C级/邪恶潜水鳐.md","filePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/3.C级/邪恶潜水鳐.md"}'),s={name:"4.资源分区/7.物品与装备/7.载具及随从/随从/3.C级/邪恶潜水鳐.md"};function o(d,b,i,l,_,c){return a(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"邪恶潜水鳐",tabindex:"-1"},[p("邪恶潜水鳐 "),r("a",{class:"header-anchor",href:"#邪恶潜水鳐","aria-label":'Permalink to "邪恶潜水鳐"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风024")])])],-1),n('<h1 id="邪恶潜水鳐-1" tabindex="-1">邪恶潜水鳐 <a class="header-anchor" href="#邪恶潜水鳐-1" aria-label="Permalink to &quot;邪恶潜水鳐&quot;">​</a></h1><p>邪恶潜水鳐<br> C级随从<br> C+2000<br> 该随从可自由行动<br> 鳐鱼型镜怪物。4000AP。拥有在水中活动与空中飞行的能力。所有镜怪物中体重最轻的，但却拥有承载一个假面骑士的强韧的身躯。以两端的鱼鳍作为武器，高速飞行放出强力冲撞攻击是其得意技。<br> 名称的由来是，意味着“邪恶”的“evil”与意味着潜水者的“diver”。设计原型是漫画版《人造人间电脑奇侠》中登场的“鳐鱼机器人”。</p><p>随从体积：5</p><p>随从属性：<br> 生理属性<br> 力量：9<br> 敏捷：11<br> 耐力：11<br> 心智属性<br> 智力：6<br> 感知：9<br> 决心：6<br> 互动属性<br> 风度：6<br> 操控：9<br> 沉着：6</p><p>随从技能：<br> 生理系<br> 运动8<br> 专业：反射8 游泳5<br> 求生5<br> 专业：强韧5<br> 射击1<br> 专业：<br> 武技8<br> 专业：翼切8</p><p>心智系<br> 学识5<br> 专业：身体掌握5<br> 器用1<br> 专业：<br> 手艺1<br> 专业：<br> 专注5<br> 专业：意志5</p><p>互动系<br> 洞察5<br> 专业：侦查5<br> 隐秘1<br> 专业：<br> 表达1<br> 专业：<br> 社交1<br> 专业</p><p>衍生属性值<br> 体积<br> 速度 （力量【9】+敏捷【11】+体积【5】+每1点敏捷上的附加获得3移动速度）=31<br> 先攻 （敏捷【11】+沉着【6】）= 17<br> 防御 （敏捷感知的平均值【10】+较高者的附加成功【2】）=10+2<br> 生命值 （耐力【11】+体积【5】+耐力附加【2】×5）=26<br> 意志力池 （决心【6】+沉着【6】+决心附加【1】×2）=12<br> 意志 （决心【6】+专注+意志【10+2】）= 19+3<br> 反射 （敏捷【11】+运动+反射【13+2】）= 24+4<br> 强韧 （耐力【11】+生存+强韧【10+2】）= 21+4<br> 侦查 （感知【9】+洞察+侦查【10+2】）= 19+3<br> 敏感范围 （感知【9】*20米+感知上的附加成功【1】*20米）=200米</p><p>攻击预设：<br> 近身翼切：9+8+8+5=30+4 范围：近战</p><p>防御预设：<br> 基础防御：10+2</p><p>专长：<br> 鳐鱼型怪兽：其本身是鳐鱼类型的怪兽所以自然具有在水中自由游动和黑暗视物的能力，在水中游泳速度等同于基础移动速度，并且自带水下呼吸和黑暗视觉。因为鳐鱼自带的发电器官，所以使得邪恶潜水鳐的近战攻击会附带二分之一的麻痹点数。而作为怪兽使得邪恶潜水鳐的两个翼有着3L的武器伤害。</p><p>飞空生物：虽然是一只鳐鱼型怪兽但是邪恶潜水鳐仍然具有着如同在海里一样随意畅游的在天空之中随意畅游的能力，其具有完美飞行特性。</p><p>镜怪兽空间：因为镜怪兽天生便在镜世界之中生存，所以自然而然的学会了如何控制自己身体之上的反光面开辟一份独属于自己的10立方米空间的能力，其中不能装独立单位，使用者放入/取出物品至少是一个迅捷动作。</p><p>邪恶尾鞭<br> C+2000<br> C级武器<br> Raia所使用的模仿了“邪恶潜鳐”的尾部的鞭状武器。2000AP。能放出高压电流，被直接打中的人会因冲击而陷入活动停止状态。<br> 类型：长鞭<br> 基础属性；11L 轻灵<br> 体积：3<br> 高压电流：武器之中附带着邪恶潜水鳐的雷电之力，每次攻击都会附带着其身上强大的高压电流，使敌人感觉到酥麻的感觉，因此你使用该武器进行攻击时会附带二分之一的麻痹点数。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',16)])])}const m=e(s,[["render",o]]);export{f as __pageData,m as default};
